module binary_adder(
    input [3:0] A,
    input [3:0] B,
    input CIN,
    output reg [3:0] S,
    output reg COUT
);

    reg obf_CARRY;

    always @(*) begin
        S[0] = A[0] ^ B[0] ^ CIN;
        obf_CARRY = (A[0] & B[0]) | (A[0] & CIN) | (B[0] & CIN);
        S[1] = A[1] ^ B[1] ^ obf_CARRY;
        obf_CARRY = (A[1] & B[1]) | (A[1] & obf_CARRY) | (B[1] & obf_CARRY);
        S[2] = A[2] ^ B[2] ^ obf_CARRY;
        obf_CARRY = (A[2] & B[2]) | (A[2] & obf_CARRY) | (B[2] & obf_CARRY);
        S[3] = A[3] ^ B[3] ^ obf_CARRY;
        COUT = (A[3] & B[3]) | (A[3] & obf_CARRY) | (B[3] & obf_CARRY);
    end

endmodule
